import{_ as e,c as o,o as n,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Revisão de Planos: Revise Visualmente Planos de IA | Plannotator","description":"Aprenda a funcionalidade de revisão de planos do Plannotator. Use a interface visual para revisar planos gerados por IA, adicione anotações para aprovar ou rejeitar, e domine a diferença entre Approve e Request Changes.","frontmatter":{"title":"Revisão de Planos: Revise Visualmente Planos de IA | Plannotator","subtitle":"Fundamentos da Revisão de Planos: Revise Visualmente Planos de IA","description":"Aprenda a funcionalidade de revisão de planos do Plannotator. Use a interface visual para revisar planos gerados por IA, adicione anotações para aprovar ou rejeitar, e domine a diferença entre Approve e Request Changes.","sidebarTitle":"Aprenda a Revisar Planos em 5 min","tags":["Revisão de Planos","Revisão Visual","Anotações","Aprovação","Rejeição","Claude Code","OpenCode"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"pt/backnotprop/plannotator/platforms/plan-review-basics/index.md","filePath":"pt/backnotprop/plannotator/platforms/plan-review-basics/index.md"}'),t={name:"pt/backnotprop/plannotator/platforms/plan-review-basics/index.md"};function r(i,a,l,p,d,c){return n(),o("div",null,[...a[0]||(a[0]=[s(`<h1 id="fundamentos-da-revisao-de-planos-revise-visualmente-planos-de-ia" tabindex="-1">Fundamentos da Revisão de Planos: Revise Visualmente Planos de IA <a class="header-anchor" href="#fundamentos-da-revisao-de-planos-revise-visualmente-planos-de-ia" aria-label="Permalink to &quot;Fundamentos da Revisão de Planos: Revise Visualmente Planos de IA&quot;">​</a></h1><h2 id="o-que-voce-vai-aprender" tabindex="-1">O Que Você Vai Aprender <a class="header-anchor" href="#o-que-voce-vai-aprender" aria-label="Permalink to &quot;O Que Você Vai Aprender&quot;">​</a></h2><ul><li>✅ Usar a interface visual do Plannotator para revisar planos gerados por IA</li><li>✅ Selecionar texto do plano e adicionar diferentes tipos de anotações (excluir, substituir, comentar)</li><li>✅ Aprovar planos para que a IA continue a implementação</li><li>✅ Rejeitar planos, enviando anotações como feedback para a IA</li><li>✅ Entender os cenários de uso e diferenças entre tipos de anotações</li></ul><h2 id="seu-problema-atual" tabindex="-1">Seu Problema Atual <a class="header-anchor" href="#seu-problema-atual" aria-label="Permalink to &quot;Seu Problema Atual&quot;">​</a></h2><p><strong>Problema 1</strong>: Planos de implementação gerados por IA são difíceis de ler no terminal—muito texto, estrutura confusa, revisão cansativa.</p><p><strong>Problema 2</strong>: Ao dar feedback para a IA, você só pode descrever em texto &quot;exclua o parágrafo 3&quot;, &quot;modifique esta função&quot;—alto custo de comunicação, e a IA pode entender errado.</p><p><strong>Problema 3</strong>: Algumas partes do plano não precisam de modificação, outras precisam de substituição, outras precisam de comentários, mas não há ferramenta para estruturar esse feedback.</p><p><strong>Problema 4</strong>: Você não sabe como informar a IA se aprovou o plano ou se precisa de modificações.</p><p><strong>O Plannotator pode ajudar</strong>:</p><ul><li>Interface visual substitui leitura no terminal, estrutura clara</li><li>Selecione texto para adicionar anotações (excluir, substituir, comentar), feedback preciso</li><li>Anotações são automaticamente convertidas em dados estruturados, a IA entende sua intenção com precisão</li><li>Aprove ou rejeite com um clique, a IA responde imediatamente</li></ul><h2 id="quando-usar-esta-tecnica" tabindex="-1">Quando Usar Esta Técnica <a class="header-anchor" href="#quando-usar-esta-tecnica" aria-label="Permalink to &quot;Quando Usar Esta Técnica&quot;">​</a></h2><p><strong>Cenários de uso</strong>:</p><ul><li>AI Agent completa o plano e chama <code>ExitPlanMode</code> (Claude Code)</li><li>AI Agent chama a ferramenta <code>submit_plan</code> (OpenCode)</li><li>Precisa revisar planos de implementação gerados por IA</li><li>Precisa dar feedback preciso sobre modificações no plano</li></ul><p><strong>Cenários não aplicáveis</strong>:</p><ul><li>Deixar a IA implementar código diretamente (pulando a revisão do plano)</li><li>Já aprovou o plano, precisa revisar as mudanças reais no código (use a funcionalidade de revisão de código)</li></ul><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação Antes de Começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação Antes de Começar&quot;">​</a></h2><p><strong>Pré-requisitos</strong>:</p><ul><li>✅ CLI do Plannotator instalado (veja <a href="./../start/getting-started/">Início Rápido</a>)</li><li>✅ Plugin Claude Code ou OpenCode configurado (veja o guia de instalação correspondente)</li><li>✅ AI Agent suporta revisão de planos (Claude Code 2.1.7+ ou OpenCode)</li></ul><p><strong>Como acionar</strong>:</p><ul><li><strong>Claude Code</strong>: Após a IA completar o plano, ela automaticamente chama <code>ExitPlanMode</code>, e o Plannotator inicia automaticamente</li><li><strong>OpenCode</strong>: A IA chama a ferramenta <code>submit_plan</code>, e o Plannotator inicia automaticamente</li></ul><h2 id="conceito-central" tabindex="-1">Conceito Central <a class="header-anchor" href="#conceito-central" aria-label="Permalink to &quot;Conceito Central&quot;">​</a></h2><h3 id="o-que-e-revisao-de-planos" tabindex="-1">O Que é Revisão de Planos <a class="header-anchor" href="#o-que-e-revisao-de-planos" aria-label="Permalink to &quot;O Que é Revisão de Planos&quot;">​</a></h3><p><strong>Revisão de Planos</strong> é a funcionalidade central do Plannotator, usada para revisar visualmente planos de implementação gerados por IA.</p><div class="info custom-block"><p class="custom-block-title">Por que precisamos de revisão de planos?</p><p>Após a IA gerar um plano, ela geralmente pergunta &quot;Este plano está bom?&quot; ou &quot;Devo começar a implementação?&quot;. Sem uma ferramenta visual, você só pode ler o plano em texto puro no terminal e responder com feedback vago como &quot;ok&quot;, &quot;não, modifique XX&quot;. O Plannotator permite que você visualize o plano em uma interface visual, selecione precisamente as partes que precisam de modificação, adicione anotações estruturadas, e a IA entende sua intenção mais facilmente.</p></div><h3 id="fluxo-de-trabalho" tabindex="-1">Fluxo de Trabalho <a class="header-anchor" href="#fluxo-de-trabalho" aria-label="Permalink to &quot;Fluxo de Trabalho&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (gera plano)  │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ ExitPlanMode / submit_plan</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│ Plannotator UI  │  ← navegador abre automaticamente</span></span>
<span class="line"><span>│                 │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Conteúdo   │  │</span></span>
<span class="line"><span>│ │ do Plano   │  │</span></span>
<span class="line"><span>│ │ (Markdown) │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       │ selecionar texto</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Adicionar  │  │</span></span>
<span class="line"><span>│ │ Anotação   │  │</span></span>
<span class="line"><span>│ │ Delete/    │  │</span></span>
<span class="line"><span>│ │ Replace/   │  │</span></span>
<span class="line"><span>│ │ Comment    │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Decisão   │  │</span></span>
<span class="line"><span>│ │ Approve/  │  │</span></span>
<span class="line"><span>│ │ Request   │  │</span></span>
<span class="line"><span>│ │ Changes   │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;allow&quot;} ou</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (continua     │</span></span>
<span class="line"><span>│  implementação)│</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><h3 id="tipos-de-anotacoes" tabindex="-1">Tipos de Anotações <a class="header-anchor" href="#tipos-de-anotacoes" aria-label="Permalink to &quot;Tipos de Anotações&quot;">​</a></h3><p>O Plannotator suporta quatro tipos de anotações, cada um com um propósito diferente:</p><table tabindex="0"><thead><tr><th>Tipo de Anotação</th><th>Propósito</th><th>Feedback que a IA Recebe</th></tr></thead><tbody><tr><td><strong>Delete</strong></td><td>Excluir conteúdo desnecessário</td><td>&quot;Excluir: [texto selecionado]&quot;</td></tr><tr><td><strong>Replace</strong></td><td>Substituir por conteúdo melhor</td><td>&quot;Substituir: [texto selecionado] por [texto que você digitou]&quot;</td></tr><tr><td><strong>Comment</strong></td><td>Comentar uma seção, sem exigir modificação</td><td>&quot;Comentário: [texto selecionado]. Nota: [seu comentário]&quot;</td></tr><tr><td><strong>Global Comment</strong></td><td>Comentário global, não associado a texto específico</td><td>&quot;Comentário Global: [seu comentário]&quot;</td></tr></tbody></table><h3 id="approve-vs-request-changes" tabindex="-1">Approve vs Request Changes <a class="header-anchor" href="#approve-vs-request-changes" aria-label="Permalink to &quot;Approve vs Request Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tipo de Decisão</th><th>Ação</th><th>Feedback que a IA Recebe</th><th>Cenário Aplicável</th></tr></thead><tbody><tr><td><strong>Approve</strong></td><td>Clique no botão Approve</td><td><code>{&quot;behavior&quot;: &quot;allow&quot;}</code></td><td>Plano está ok, aprovar diretamente</td></tr><tr><td><strong>Request Changes</strong></td><td>Clique no botão Request Changes</td><td><code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></td><td>Há partes que precisam de modificação</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Diferenças entre Claude Code e OpenCode</p><ul><li><strong>Claude Code</strong>: Ao aprovar, as anotações não são enviadas (anotações são ignoradas)</li><li><strong>OpenCode</strong>: Ao aprovar, as anotações podem ser enviadas como notas (opcional)</li></ul><p><strong>Ao rejeitar o plano</strong>: Em ambas as plataformas, as anotações são enviadas para a IA</p></div><h2 id="siga-comigo" tabindex="-1">Siga Comigo <a class="header-anchor" href="#siga-comigo" aria-label="Permalink to &quot;Siga Comigo&quot;">​</a></h2><h3 id="passo-1-acionar-a-revisao-de-planos" tabindex="-1">Passo 1: Acionar a Revisão de Planos <a class="header-anchor" href="#passo-1-acionar-a-revisao-de-planos" aria-label="Permalink to &quot;Passo 1: Acionar a Revisão de Planos&quot;">​</a></h3><p><strong>Exemplo com Claude Code</strong>:</p><p>No Claude Code, converse com a IA e peça para ela gerar um plano de implementação:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Usuário: Ajude-me a criar um plano de implementação para um módulo de autenticação de usuários</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: Ok, aqui está o plano de implementação:</span></span>
<span class="line"><span>1. Criar modelo de usuário</span></span>
<span class="line"><span>2. Implementar API de registro</span></span>
<span class="line"><span>3. Implementar API de login</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(IA chama ExitPlanMode)</span></span></code></pre></div><p><strong>Exemplo com OpenCode</strong>:</p><p>No OpenCode, a IA automaticamente chama a ferramenta <code>submit_plan</code>.</p><p><strong>O que você deve ver</strong>:</p><ol><li>O navegador abre automaticamente a interface do Plannotator</li><li>Exibe o conteúdo do plano gerado pela IA (formato Markdown)</li><li>Na parte inferior da página há botões &quot;Approve&quot; e &quot;Request Changes&quot;</li></ol><h3 id="passo-2-navegar-pelo-conteudo-do-plano" tabindex="-1">Passo 2: Navegar pelo Conteúdo do Plano <a class="header-anchor" href="#passo-2-navegar-pelo-conteudo-do-plano" aria-label="Permalink to &quot;Passo 2: Navegar pelo Conteúdo do Plano&quot;">​</a></h3><p>Visualize o plano no navegador:</p><ul><li>O plano é renderizado em formato Markdown, incluindo títulos, parágrafos, listas, blocos de código</li><li>Você pode rolar para ver o plano inteiro</li><li>Suporta alternância entre modo claro/escuro (clique no botão de alternância de tema no canto superior direito)</li></ul><h3 id="passo-3-selecionar-texto-do-plano-e-adicionar-anotacoes" tabindex="-1">Passo 3: Selecionar Texto do Plano e Adicionar Anotações <a class="header-anchor" href="#passo-3-selecionar-texto-do-plano-e-adicionar-anotacoes" aria-label="Permalink to &quot;Passo 3: Selecionar Texto do Plano e Adicionar Anotações&quot;">​</a></h3><p><strong>Adicionar anotação Delete</strong>:</p><ol><li>Use o mouse para selecionar o texto que precisa ser excluído no plano</li><li>Na barra de ferramentas que aparece, clique no botão <strong>Delete</strong></li><li>O texto será marcado com estilo de exclusão (tachado vermelho)</li></ol><p><strong>Adicionar anotação Replace</strong>:</p><ol><li>Use o mouse para selecionar o texto que precisa ser substituído no plano</li><li>Na barra de ferramentas que aparece, clique no botão <strong>Replace</strong></li><li>Na caixa de entrada que aparece, digite o conteúdo de substituição</li><li>Pressione Enter ou clique em confirmar</li><li>O texto original será marcado com estilo de substituição (fundo amarelo), e o conteúdo de substituição aparecerá abaixo</li></ol><p><strong>Adicionar anotação Comment</strong>:</p><ol><li>Use o mouse para selecionar o texto que precisa de comentário no plano</li><li>Na barra de ferramentas que aparece, clique no botão <strong>Comment</strong></li><li>Na caixa de entrada que aparece, digite o conteúdo do comentário</li><li>Pressione Enter ou clique em confirmar</li><li>O texto será marcado com estilo de comentário (destaque azul), e o comentário aparecerá na barra lateral</li></ol><p><strong>Adicionar Global Comment</strong>:</p><ol><li>Clique no botão <strong>Add Global Comment</strong> no canto superior direito da página</li><li>Na caixa de entrada que aparece, digite o conteúdo do comentário global</li><li>Pressione Enter ou clique em confirmar</li><li>O comentário aparecerá na seção &quot;Global Comments&quot; da barra lateral</li></ol><p><strong>O que você deve ver</strong>:</p><ul><li>Após selecionar o texto, uma barra de ferramentas aparece imediatamente (Delete, Replace, Comment)</li><li>Após adicionar anotações, o texto exibe o estilo correspondente (tachado, cor de fundo, destaque)</li><li>A barra lateral exibe a lista de todas as anotações, você pode clicar para ir à posição correspondente</li><li>Você pode clicar no botão <strong>excluir</strong> ao lado da anotação para removê-la</li></ul><h3 id="passo-4-aprovar-o-plano" tabindex="-1">Passo 4: Aprovar o Plano <a class="header-anchor" href="#passo-4-aprovar-o-plano" aria-label="Permalink to &quot;Passo 4: Aprovar o Plano&quot;">​</a></h3><p><strong>Se o plano estiver ok</strong>:</p><p>Clique no botão <strong>Approve</strong> na parte inferior da página.</p><p><strong>O que você deve ver</strong>:</p><ul><li>O navegador fecha automaticamente (atraso de 1,5 segundos)</li><li>O terminal do Claude Code/OpenCode mostra que o plano foi aprovado</li><li>A IA continua a implementar o plano</li></ul><div class="info custom-block"><p class="custom-block-title">Comportamento do Approve</p><ul><li><strong>Claude Code</strong>: Envia apenas <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>, anotações são ignoradas</li><li><strong>OpenCode</strong>: Envia <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>, anotações podem ser enviadas como notas (opcional)</li></ul></div><h3 id="passo-5-rejeitar-o-plano-request-changes" tabindex="-1">Passo 5: Rejeitar o Plano (Request Changes) <a class="header-anchor" href="#passo-5-rejeitar-o-plano-request-changes" aria-label="Permalink to &quot;Passo 5: Rejeitar o Plano (Request Changes)&quot;">​</a></h3><p><strong>Se o plano precisar de modificações</strong>:</p><ol><li>Adicione as anotações necessárias (Delete, Replace, Comment)</li><li>Clique no botão <strong>Request Changes</strong> na parte inferior da página</li><li>O navegador exibirá um diálogo de confirmação</li></ol><p><strong>O que você deve ver</strong>:</p><ul><li>O diálogo de confirmação mostra &quot;Send X annotations to AI?&quot;</li><li>Após confirmar, o navegador fecha automaticamente</li><li>O terminal do Claude Code/OpenCode mostra o conteúdo do feedback</li><li>A IA modificará o plano com base no feedback</li></ul><div class="tip custom-block"><p class="custom-block-title">Comportamento do Request Changes</p><ul><li><strong>Claude Code</strong> e <strong>OpenCode</strong>: Ambos enviam <code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></li><li>As anotações são convertidas em texto Markdown estruturado</li><li>A IA modificará o plano e chamará ExitPlanMode/submit_plan novamente</li></ul></div><h3 id="passo-6-visualizar-o-conteudo-do-feedback-opcional" tabindex="-1">Passo 6: Visualizar o Conteúdo do Feedback (Opcional) <a class="header-anchor" href="#passo-6-visualizar-o-conteudo-do-feedback-opcional" aria-label="Permalink to &quot;Passo 6: Visualizar o Conteúdo do Feedback (Opcional)&quot;">​</a></h3><p>Se você quiser ver o conteúdo do feedback que o Plannotator enviou para a IA, pode verificar no terminal:</p><p><strong>Claude Code</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan rejected by user</span></span>
<span class="line"><span>Please modify the plan based on the following feedback:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[conteúdo estruturado das anotações]</span></span></code></pre></div><p><strong>OpenCode</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;feedback&gt;</span></span>
<span class="line"><span>[conteúdo estruturado das anotações]</span></span>
<span class="line"><span>&lt;/feedback&gt;</span></span></code></pre></div><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>Após completar os passos acima, você deve ser capaz de:</p><ul><li>[ ] Quando a IA aciona a revisão de planos, o navegador abre automaticamente a interface do Plannotator</li><li>[ ] Selecionar texto do plano e adicionar anotações Delete, Replace, Comment</li><li>[ ] Adicionar Global Comment</li><li>[ ] Ver todas as anotações na barra lateral e ir às posições correspondentes</li><li>[ ] Clicar em Approve, o navegador fecha, a IA continua a implementação</li><li>[ ] Clicar em Request Changes, o navegador fecha, a IA modifica o plano</li></ul><p><strong>Se algum passo falhar</strong>, veja:</p><ul><li><a href="./../../faq/common-problems/">Problemas Comuns</a></li><li><a href="./../../start/installation-claude-code/">Guia de Instalação do Claude Code</a></li><li><a href="./../../start/installation-opencode/">Guia de Instalação do OpenCode</a></li></ul><h2 id="armadilhas-comuns" tabindex="-1">Armadilhas Comuns <a class="header-anchor" href="#armadilhas-comuns" aria-label="Permalink to &quot;Armadilhas Comuns&quot;">​</a></h2><p><strong>Erro comum 1</strong>: Após selecionar o texto, a barra de ferramentas não aparece</p><p><strong>Causa</strong>: Pode ser porque você selecionou texto dentro de um bloco de código, ou o texto selecionado abrange múltiplos elementos.</p><p><strong>Solução</strong>:</p><ul><li>Tente selecionar texto dentro de um único parágrafo ou item de lista</li><li>Para blocos de código, use anotação Comment, não selecione múltiplas linhas</li></ul><p><strong>Erro comum 2</strong>: Após adicionar anotação Replace, o conteúdo de substituição não aparece</p><p><strong>Causa</strong>: A caixa de entrada do conteúdo de substituição pode não ter sido enviada corretamente.</p><p><strong>Solução</strong>:</p><ul><li>Após digitar o conteúdo de substituição, pressione Enter ou clique no botão de confirmação</li><li>Verifique se o conteúdo de substituição aparece na barra lateral</li></ul><p><strong>Erro comum 3</strong>: Após clicar em Approve ou Request Changes, o navegador não fecha</p><p><strong>Causa</strong>: Pode ser um erro do servidor ou problema de rede.</p><p><strong>Solução</strong>:</p><ul><li>Verifique se há mensagens de erro no terminal</li><li>Feche o navegador manualmente</li><li>Se o problema persistir, veja <a href="./../../faq/troubleshooting/">Solução de Problemas</a></li></ul><p><strong>Erro comum 4</strong>: Após a IA receber o feedback, ela não modifica de acordo com as anotações</p><p><strong>Causa</strong>: A IA pode não ter entendido corretamente a intenção das anotações.</p><p><strong>Solução</strong>:</p><ul><li>Tente usar anotações mais explícitas (Replace é mais explícito que Comment)</li><li>Use Comment para adicionar explicações detalhadas</li><li>Se o problema persistir, você pode rejeitar o plano novamente e ajustar o conteúdo das anotações</li></ul><p><strong>Erro comum 5</strong>: Após adicionar múltiplas anotações Delete, a IA só excluiu parte do conteúdo</p><p><strong>Causa</strong>: Múltiplas anotações Delete podem ter sobreposição ou conflito.</p><p><strong>Solução</strong>:</p><ul><li>Certifique-se de que o intervalo de texto de cada anotação Delete não se sobreponha</li><li>Se precisar excluir uma grande seção de conteúdo, selecione o parágrafo inteiro de uma vez</li></ul><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><p>A Revisão de Planos é a funcionalidade central do Plannotator, permitindo que você revise visualmente planos gerados por IA:</p><p><strong>Operações principais</strong>:</p><ol><li><strong>Acionar</strong>: A IA chama <code>ExitPlanMode</code> ou <code>submit_plan</code>, o navegador abre automaticamente a interface</li><li><strong>Navegar</strong>: Visualize o conteúdo do plano na interface visual (formato Markdown)</li><li><strong>Anotar</strong>: Selecione texto, adicione Delete, Replace, Comment ou Global Comment</li><li><strong>Decidir</strong>: Clique em Approve (aprovar) ou Request Changes (rejeitar)</li><li><strong>Feedback</strong>: As anotações são convertidas em dados estruturados, a IA continua ou modifica o plano com base no feedback</li></ol><p><strong>Tipos de anotações</strong>:</p><ul><li><strong>Delete</strong>: Excluir conteúdo desnecessário</li><li><strong>Replace</strong>: Substituir por conteúdo melhor</li><li><strong>Comment</strong>: Comentar uma seção, sem exigir modificação</li><li><strong>Global Comment</strong>: Comentário global, não associado a texto específico</li></ul><p><strong>Tipos de decisão</strong>:</p><ul><li><strong>Approve</strong>: Plano está ok, aprovar diretamente (Claude Code ignora anotações)</li><li><strong>Request Changes</strong>: Há partes que precisam de modificação, anotações são enviadas para a IA</li></ul><h2 id="previa-da-proxima-licao" tabindex="-1">Prévia da Próxima Lição <a class="header-anchor" href="#previa-da-proxima-licao" aria-label="Permalink to &quot;Prévia da Próxima Lição&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos <strong><a href="./../plan-review-annotations/">Adicionar Anotações ao Plano</a></strong>.</p><p>Você aprenderá:</p><ul><li>Como usar precisamente anotações Delete, Replace, Comment</li><li>Como adicionar anotações de imagem</li><li>Como editar e excluir anotações</li><li>Melhores práticas e cenários comuns de anotações</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código-Fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código-Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Interface de Revisão de Planos</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>Definição de Tipos de Anotação</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/types.ts#L1-L70" target="_blank" rel="noreferrer"><code>packages/ui/types.ts</code></a></td><td>1-70</td></tr><tr><td>Servidor de Revisão de Planos</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L91-L310" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>91-310</td></tr><tr><td>API: Obter Conteúdo do Plano</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L132-L134" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>132-134</td></tr><tr><td>API: Aprovar Plano</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L201-L277" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>201-277</td></tr><tr><td>API: Rejeitar Plano</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L280-L309" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>280-309</td></tr><tr><td>Componente Viewer</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L1-L100" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></td><td>1-100</td></tr><tr><td>Componente AnnotationPanel</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationPanel.tsx#L1-L50" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationPanel.tsx</code></a></td><td>1-50</td></tr></tbody></table><p><strong>Tipos principais</strong>:</p><ul><li><code>AnnotationType</code>: Enum de tipos de anotação (DELETION, INSERTION, REPLACEMENT, COMMENT, GLOBAL_COMMENT) (<code>packages/ui/types.ts:1-7</code>)</li><li><code>Annotation</code>: Interface de anotação (<code>packages/ui/types.ts:11-33</code>)</li><li><code>Block</code>: Interface de bloco do plano (<code>packages/ui/types.ts:35-44</code>)</li></ul><p><strong>Funções principais</strong>:</p><ul><li><code>startPlannotatorServer()</code>: Inicia o servidor de revisão de planos (<code>packages/server/index.ts:91</code>)</li><li><code>parseMarkdownToBlocks()</code>: Converte Markdown em Blocks (<code>packages/ui/utils/parser.ts</code>)</li></ul><p><strong>Rotas da API</strong>:</p><ul><li><code>GET /api/plan</code>: Obter conteúdo do plano (<code>packages/server/index.ts:132</code>)</li><li><code>POST /api/approve</code>: Aprovar plano (<code>packages/server/index.ts:201</code>)</li><li><code>POST /api/deny</code>: Rejeitar plano (<code>packages/server/index.ts:280</code>)</li></ul><p><strong>Regras de negócio</strong>:</p><ul><li>Claude Code não envia anotações ao aprovar (<code>apps/hook/server/index.ts:132</code>)</li><li>OpenCode pode enviar anotações como notas ao aprovar (<code>apps/opencode-plugin/index.ts:270</code>)</li><li>Anotações são sempre enviadas ao rejeitar o plano (<code>apps/hook/server/index.ts:154</code>)</li></ul></details>`,112)])])}const g=e(t,[["render",r]]);export{m as __pageData,g as default};
